SELECT A.* FROM ( SELECT GETCOMCODE(HD.GATE_CD, 'M070', 'BID', 0, #{ses.langCd}) AS TYPE , 'BID' AS RFX_TYPE , HD.BUYER_CD ,getBuyerNames(HD.GATE_CD, HD.BUYER_CD, 'BID', HD.BID_NUM, HD.BID_CNT, null, #{ses.langCd}) AS BUYER_NM , HD.ANN_NO , HD.ANN_ITEM , HD.ANN_DATE , HD.CONT_TYPE1 ,GETCOMCODE(HD.GATE_CD, 'M301', HD.CONT_TYPE1, 0, #{ses.langCd}) AS CONT_TYPE1_LOC , HD.CONT_TYPE2 ,GETCOMCODE(HD.GATE_CD, 'M302', HD.CONT_TYPE2, 0, #{ses.langCd}) AS CONT_TYPE2_LOC , HD.CONT_TYPE3 ,GETCOMCODE(HD.GATE_CD, 'M303', HD.CONT_TYPE3, 0, #{ses.langCd}) AS CONT_TYPE3_LOC , SUBSTR(HD.APP_BEGIN_DATE, 1, 4) '-' SUBSTR(HD.APP_BEGIN_DATE, 5, 2) '-' SUBSTR(HD.APP_BEGIN_DATE, 7, 2) ' ' SUBSTR(HD.APP_BEGIN_TIME, 1, 2) ':' SUBSTR(HD.APP_BEGIN_TIME, 3, 2) AS APP_BEGIN_DATETIME , SUBSTR(HD.APP_END_DATE, 1, 4) '-' SUBSTR(HD.APP_END_DATE, 5, 2) '-' SUBSTR(HD.APP_END_DATE, 7, 2) ' ' SUBSTR(HD.APP_END_TIME, 1, 2) ':' SUBSTR(HD.APP_END_TIME, 3, 2) AS APP_END_DATETIME ,(CASE WHEN ES.ESTM_CONFIRM_DATE IS NULL THEN '0' ELSE '1' END) AS BID_STATUS , HD.BID_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.BID_USER_ID, #{ses.langCd}) AS BID_USER_NM , HD.ESTM_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.ESTM_USER_ID, #{ses.langCd}) AS ESTM_USER_NM , HD.BID_NUM , HD.BID_CNT ,(ES.SIGN_STATUS,'') AS SIGN_STATUS ,(HD.ESTM_TYPE,'ES') AS ESTM_TYPE ,(CASE WHEN ES.ESTM_CONFIRM_DATE IS NULL THEN '0' ELSE '1' END) AS BID_STATUS_LOC , HD.BID_STATUS AS BID_STATUS2 , ES.APP_DOC_NUM , ES.APP_DOC_CNT FROM STOCBDHD HD LEFT JOIN STOCBDES ES ON (HD.GATE_CD = ES.GATE_CD AND HD.BUYER_CD = ES.BUYER_CD AND HD.BID_NUM = ES.BID_NUM AND HD.BID_CNT = ES.BID_CNT AND ES.DEL_FLAG = '0') WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BUYER_CD = #{ses.companyCd} AND HD.SIGN_STATUS = 'E' AND HD.BID_STATUS NOT IN ('9999', '2303', '2330') -- 취소공고건, 취소공고작성중, 취소공고확정건 제외 AND HD.DEL_FLAG = '0' AND (HD.ESTM_TYPE,'ES') != 'ES' -- 예가 생략 아니것
AND EXISTS (SELECT '1' FROM STOCBDDT WHERE GATE_CD = HD.GATE_CD AND BUYER_CD = HD.BUYER_CD AND BID_NUM = HD.BID_NUM AND BID_CNT = HD.BID_CNT AND PR_BUYER_CD = #{BUYER_CD} AND DEL_FLAG = '0')
AND EXISTS (SELECT '1' FROM STOCBDDT WHERE GATE_CD = HD.GATE_CD AND BUYER_CD = HD.BUYER_CD AND BID_NUM = HD.BID_NUM AND BID_CNT = HD.BID_CNT AND UPPER(getCustName(GATE_CD, PR_BUYER_CD)) LIKE '%' UPPER(#{BUYER_NM}) '%' AND DEL_FLAG = '0')
UNION ALL
SELECT GETCOMCODE(HD.GATE_CD, 'M070', HD.RFX_TYPE, 0, #{ses.langCd}) AS TYPE , HD.RFX_TYPE , HD.BUYER_CD ,getBuyerNames(HD.GATE_CD, HD.BUYER_CD, 'RFX', HD.RFX_NUM, HD.RFX_CNT, null, #{ses.langCd}) AS BUYER_NM , HD.RFX_NUM AS ANN_NO , HD.RFX_SUBJECT AS ANN_ITEM ,(HD.SIGN_DATE,'YYYYMMDD') AS ANN_DATE , HD.VENDOR_OPEN_TYPE AS CONT_TYPE1 ,GETCOMCODE(HD.GATE_CD, 'M301', HD.VENDOR_OPEN_TYPE, 0, #{ses.langCd}) AS CONT_TYPE1_LOC , 'LP' AS CONT_TYPE2 ,(CASE WHEN HD.RFX_TYPE = 'RPC' or HD.RFX_TYPE = 'RCA' or HD.RFX_TYPE = 'RFQ' or HD.RFX_TYPE = 'RYQ' THEN NULL ELSE GETCOMCODE(HD.GATE_CD, 'M301', 'LP', 0, #{ses.langCd}) END) AS CONT_TYPE2_LOC , HD.AMT_TYPE AS CONT_TYPE3 ,GETCOMCODE(HD.GATE_CD, 'M303', HD.AMT_TYPE, 0, #{ses.langCd}) AS CONT_TYPE3_LOC ,(RFX_START_DATE, 'YYYY-MM-DD HH24:MI') AS APP_BEGIN_DATETIME ,(RFX_END_DATE, 'YYYY-MM-DD HH24:MI') AS APP_END_DATETIME ,(CASE WHEN ES.ESTM_CONFIRM_DATE IS NULL THEN '0' ELSE '1' END) AS BID_STATUS , HD.CTRL_USER_ID AS BID_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.CTRL_USER_ID, #{ses.langCd}) AS BID_USER_NM , HD.ESTM_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.ESTM_USER_ID, #{ses.langCd}) AS ESTM_USER_NM , HD.RFX_NUM AS BID_NUM , HD.RFX_CNT AS BID_CNT ,(ES.SIGN_STATUS,'') AS SIGN_STATUS ,(CASE WHEN (HD.EST_PRICE_TYPE,'0') = '1' THEN 'SE' ELSE 'SE' END) AS ESTM_TYPE ,(CASE WHEN ES.ESTM_CONFIRM_DATE IS NULL THEN '0' ELSE '1' END) AS BID_STATUS_LOC , HD.PROGRESS_CD AS BID_STATUS2 , ES.APP_DOC_NUM , ES.APP_DOC_CNT FROM STOCRQHD HD LEFT JOIN STOCBDES ES ON (HD.GATE_CD = ES.GATE_CD AND HD.BUYER_CD = ES.BUYER_CD AND HD.RFX_NUM = ES.BID_NUM AND HD.RFX_CNT = ES.BID_CNT AND ES.DEL_FLAG = '0') WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BUYER_CD = #{ses.companyCd} AND HD.RFX_CNT = '1' AND HD.SIGN_STATUS = 'E' AND HD.DEL_FLAG = '0' AND (HD.EST_PRICE_TYPE,'0') != '0' -- 예가 생략 아니것
AND EXISTS ( SELECT '1'FROM STOCRQDT WHERE GATE_CD = HD.GATE_CD AND BUYER_CD = HD.BUYER_CD AND RFX_NUM = HD.RFX_NUM AND RFX_CNT = HD.RFX_CNT AND PR_BUYER_CD = #{BUYER_CD} AND DEL_FLAG = '0')
AND EXISTS (SELECT '1' FROM STOCRQDT WHERE GATE_CD = HD.GATE_CD AND BUYER_CD = HD.BUYER_CD AND RFX_NUM = HD.RFX_NUM AND RFX_CNT = HD.RFX_CNT AND UPPER(getCustName(GATE_CD, PR_BUYER_CD)) LIKE '%' UPPER(#{BUYER_NM}) '%' AND DEL_FLAG = '0')
) A WHERE 1 = 1
AND A.ANN_DATE >= (#{ANN_DATE_FROM}) AND A.ANN_DATE <= (#{ANN_DATE_TO})
AND (A.SIGN_STATUS,'') = #{SIGN_STATUS}
AND A.BID_STATUS = #{BID_STATUS}
AND UPPER(A.ANN_NO) LIKE '%' UPPER(#{ANN_NO}) '%'
AND UPPER(REPLACE(A.ANN_ITEM, ' ', '')) LIKE '%' UPPER(REPLACE(#{ANN_ITEM}, ' ', '')) '%'
AND A.BID_USER_ID = #{BID_USER_ID}
AND UPPER(A.BID_USER_NM) LIKE '%' UPPER(#{BID_USER_NM}) '%'
AND A.ESTM_USER_ID = #{ESTM_USER_ID}
AND UPPER(A.ESTM_USER_NM) LIKE '%' UPPER(#{ESTM_USER_NM}) '%'
AND A.RFX_TYPE = #{RFX_TYPE}
ORDER BY A.BID_STATUS_LOC , A.SIGN_STATUS , A.APP_END_DATETIME DESC , A.ANN_DATE DESC , A.BID_NUM DESC , A.BID_CNT

mapper.update:
UPDATE STOCBDHD SET
	  MOD_DATE     = SYSDATE
	, MOD_USER_ID  = #{ses.userId}
	, ESTM_USER_ID = #{CTRL_USER_ID}
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND BID_NUM  = #{BID_NUM}
   AND BID_CNT  = #{BID_CNT}

UPDATE STOCRQHD SET
	  MOD_DATE     = SYSDATE
	, MOD_USER_ID  = #{ses.userId}
	, ESTM_USER_ID = #{CTRL_USER_ID}
 WHERE GATE_CD  = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND RFX_NUM  = #{BID_NUM}
   AND RFX_CNT  = #{BID_CNT}

