SELECT HD.* FROM ( SELECT HD.GATE_CD , HD.BUYER_CD , HD.BID_NUM , HD.BID_CNT ,GETCOMCODE(HD.GATE_CD, 'M070', 'BID', 0, #{ses.langCd}) AS TYPE , 'BID' AS RFX_TYPE , HD.ANN_NO , HD.ANN_ITEM , HD.ANN_DATE , HD.CONT_TYPE1 ,GETCOMCODE(HD.GATE_CD, 'M301', HD.CONT_TYPE1, 0, #{ses.langCd}) AS CONT_TYPE1_LOC , HD.CONT_TYPE2 ,' / ' GETCOMCODE(HD.GATE_CD, 'M302', HD.CONT_TYPE2, 0, #{ses.langCd}) AS CONT_TYPE2_LOC , HD.CONT_TYPE3 ,' / ' GETCOMCODE(HD.GATE_CD, 'M303', HD.CONT_TYPE3, 0, #{ses.langCd}) AS CONT_TYPE3_LOC , SUBSTR(HD.APP_BEGIN_DATE, 1, 4) '-' SUBSTR(HD.APP_BEGIN_DATE, 5, 2) '-' SUBSTR(HD.APP_BEGIN_DATE, 7, 2) ' ' SUBSTR(HD.APP_BEGIN_TIME, 1, 2) ':' SUBSTR(HD.APP_BEGIN_TIME, 3, 2) AS APP_BEGIN_DATETIME , SUBSTR(HD.APP_END_DATE, 1, 4) '-' SUBSTR(HD.APP_END_DATE, 5, 2) '-' SUBSTR(HD.APP_END_DATE, 7, 2) ' ' SUBSTR(HD.APP_END_TIME, 1, 2) ':' SUBSTR(HD.APP_END_TIME, 3, 2) AS APP_END_DATETIME , HD.BID_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.BID_USER_ID, #{ses.langCd}) AS BID_USER_NM , HD.ESTM_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.ESTM_USER_ID, #{ses.langCd}) AS ESTM_USER_NM ,(HD.ESTM_TYPE, 'ES') AS ESTM_TYPE , HD.PR_AMT , HD.CUR , HD.VAT_TYPE , HD.TCO_FLAG , HD.TCO_YEAR_CNT , HD.FINA_SOLV_FLAG , HD.ESTM_LIMIT_RATE , HD.RATE_CURR , HD.RATE_SDEPT , HD.DIFF_GUAR_FLAG , HD.TECH_SCORE , HD.PRC_SCORE , HD.MIN_TECH_SCORE , HD.MIN_TOT_SCORE , HD.CONF_STD_SCORE , HD.SB_LIMIT_RATE , HD.BID_STATUS , HD.BASIC_AMT ,(ES.SIGN_STATUS, 'T') AS SIGN_STATUS ,(CASE WHEN HD.CONT_TYPE2 = 'QE' THEN HD.BASIC_AMT ELSE ES.PRESUM_AMT END) AS PRESUM_AMT , ES.RMK , ES.ATT_FILE_NUM ,ES.ESTM_PRC1_ENC AS ESTM_PRC1_ENC ,ES.ESTM_PRC2_ENC AS ESTM_PRC2_ENC ,ES.ESTM_PRC3_ENC AS ESTM_PRC3_ENC ,ES.ESTM_PRC4_ENC AS ESTM_PRC4_ENC ,ES.ESTM_PRC5_ENC AS ESTM_PRC5_ENC ,ES.ESTM_PRC6_ENC AS ESTM_PRC6_ENC ,ES.ESTM_PRC7_ENC AS ESTM_PRC7_ENC ,ES.ESTM_PRC8_ENC AS ESTM_PRC8_ENC ,ES.ESTM_PRC9_ENC AS ESTM_PRC9_ENC ,ES.ESTM_PRC10_ENC AS ESTM_PRC10_ENC ,ES.ESTM_PRC11_ENC AS ESTM_PRC11_ENC ,ES.ESTM_PRC12_ENC AS ESTM_PRC12_ENC ,ES.ESTM_PRC13_ENC AS ESTM_PRC13_ENC ,ES.ESTM_PRC14_ENC AS ESTM_PRC14_ENC ,ES.ESTM_PRC15_ENC AS ESTM_PRC15_ENC ,GETCOMCODE(HD.GATE_CD, 'M301', HD.CONT_TYPE1, 0, #{ses.langCd})
GETCOMCODE(HD.GATE_CD, 'M302', HD.CONT_TYPE2, 0, #{ses.langCd})
GETCOMCODE(HD.GATE_CD, 'M303', HD.CONT_TYPE3, 0, #{ses.langCd})
(CASE WHEN HD.TCO_FLAG = '1' THEN '(' || HD.TCO_YEAR_CNT || '년 TCO) ' END) || (CASE WHEN HD.CONT_TYPE2 = 'LP' THEN (CASE WHEN HD.FINA_SOLV_FLAG = '1' THEN ' / 예정가격비율 ' || HD.ESTM_LIMIT_RATE END) || '%, 부채비율 ' || HD.RATE_SDEPT || '%, 유동비율 ' || HD.RATE_CURR || '% / 차액보증여부 ' ||(CASE WHEN HD.DIFF_GUAR_FLAG = '1' THEN 'Y' ELSE 'N' END) ELSE '' END) || (CASE WHEN HD.CONT_TYPE2 = 'NE' THEN ' / 기술 ' || HD.TECH_SCORE || '점, 가격 ' || HD.PRC_SCORE || '점, 기술적격 ' || HD.MIN_TECH_SCORE || '점, 종합적격 ' || HD.MIN_TOT_SCORE || '점' ELSE '' END) || (CASE WHEN HD.CONT_TYPE2 = 'QE' THEN ' / 적격심사기준 ' || HD.CONF_STD_SCORE || '점, 낙찰하한율 ' || HD.SB_LIMIT_RATE || '%' ELSE '' END) AS CONT_TEXT , ES.FINAL_ESTM_PRC AS ESTM_AVGPRC_ENC , ES.APP_DOC_NUM , ES.APP_DOC_CNT FROM STOCBDHD HD LEFT JOIN STOCBDES ES ON (ES.GATE_CD = HD.GATE_CD AND ES.BUYER_CD = HD.BUYER_CD AND ES.BID_NUM = HD.BID_NUM AND ES.BID_CNT = HD.BID_CNT AND ES.DEL_FLAG = '0') WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BUYER_CD = #{BUYER_CD} AND HD.DEL_FLAG = '0'
AND HD.BID_NUM = #{BID_NUM}
AND HD.BID_CNT = #{BID_CNT}
AND ES.APP_DOC_NUM = #{APP_DOC_NUM} AND HD.BID_NUM = (SELECT MAX(BID_NUM) FROM STOCBDES WHERE GATE_CD = ES.GATE_CD AND BUYER_CD = ES.BUYER_CD AND APP_DOC_NUM = ES.APP_DOC_NUM AND DEL_FLAG = '0')
UNION ALL
SELECT HD.GATE_CD , HD.BUYER_CD , HD.RFX_NUM AS BID_NUM , HD.RFX_CNT AS BID_CNT ,GETCOMCODE(HD.GATE_CD, 'M070', HD.RFX_TYPE, 0, #{ses.langCd}) AS TYPE , HD.RFX_TYPE , HD.RFX_NUM AS ANN_NO , HD.RFX_SUBJECT AS ANN_ITEM ,(HD.SIGN_DATE,'YYYYMMDD') AS ANN_DATE , HD.VENDOR_OPEN_TYPE AS CONT_TYPE1 ,GETCOMCODE(HD.GATE_CD, 'M301', HD.VENDOR_OPEN_TYPE, 0, #{ses.langCd}) AS CONT_TYPE1_LOC , 'LP' AS CONT_TYPE2 ,'' AS CONT_TYPE2_LOC , HD.SETTLE_TYPE AS CONT_TYPE3 ,'' AS CONT_TYPE3_LOC ,(RFX_START_DATE,'YYYY-MM-DD HH24:MI') AS APP_BEGIN_DATETIME ,(RFX_END_DATE,'YYYY-MM-DD HH24:MI') AS APP_END_DATETIME , HD.CTRL_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.CTRL_USER_ID, #{ses.langCd}) AS BID_USER_NM , HD.ESTM_USER_ID ,GETUSERNAME(HD.GATE_CD, HD.ESTM_USER_ID, #{ses.langCd}) AS ESTM_USER_NM ,(CASE WHEN (HD.EST_PRICE_TYPE,'0') = '1' THEN 'SE' ELSE 'SE' END) ESTM_TYPE , HD.PR_AMT , HD.CUR , HD.VAT_TYPE , 'N' AS TCO_FLAG , null AS TCO_YEAR_CNT , null AS FINA_SOLV_FLAG , null AS ESTM_LIMIT_RATE , null AS RATE_CURR , null AS RATE_SDEPT , null AS DIFF_GUAR_FLAG , null AS TECH_SCORE , null AS PRC_SCORE , null AS MIN_TECH_SCORE , null AS MIN_TOT_SCORE , null AS CONF_STD_SCORE , null AS SB_LIMIT_RATE , null AS BID_STATUS , null AS BASIC_AMT ,(ES.SIGN_STATUS, 'T') AS SIGN_STATUS , ES.PRESUM_AMT AS PRESUM_AMT , ES.RMK , ES.ATT_FILE_NUM ,ES.ESTM_PRC1_ENC AS ESTM_PRC1_ENC ,ES.ESTM_PRC2_ENC AS ESTM_PRC2_ENC ,ES.ESTM_PRC3_ENC AS ESTM_PRC3_ENC ,ES.ESTM_PRC4_ENC AS ESTM_PRC4_ENC ,ES.ESTM_PRC5_ENC AS ESTM_PRC5_ENC ,ES.ESTM_PRC6_ENC AS ESTM_PRC6_ENC ,ES.ESTM_PRC7_ENC AS ESTM_PRC7_ENC ,ES.ESTM_PRC8_ENC AS ESTM_PRC8_ENC ,ES.ESTM_PRC9_ENC AS ESTM_PRC9_ENC ,ES.ESTM_PRC10_ENC AS ESTM_PRC10_ENC ,ES.ESTM_PRC11_ENC AS ESTM_PRC11_ENC ,ES.ESTM_PRC12_ENC AS ESTM_PRC12_ENC ,ES.ESTM_PRC13_ENC AS ESTM_PRC13_ENC ,ES.ESTM_PRC14_ENC AS ESTM_PRC14_ENC ,ES.ESTM_PRC15_ENC AS ESTM_PRC15_ENC , ' ' AS CONT_TEXT , ES.FINAL_ESTM_PRC AS ESTM_AVGPRC_ENC , ES.APP_DOC_NUM , ES.APP_DOC_CNT FROM STOCRQHD HD LEFT JOIN STOCBDES ES ON (ES.GATE_CD = HD.GATE_CD AND ES.BUYER_CD = HD.BUYER_CD AND ES.BID_NUM = HD.RFX_NUM AND ES.BID_CNT = HD.RFX_CNT AND ES.DEL_FLAG = '0') WHERE HD.GATE_CD = #{ses.gateCd} AND HD.BUYER_CD = #{BUYER_CD}
AND HD.RFX_NUM = #{BID_NUM}
AND HD.RFX_CNT = #{BID_CNT}
AND ES.APP_DOC_NUM = #{APP_DOC_NUM}
) HD WHERE 1 = 1

