MERGE STOCBDES A USING (SELECT #{ses.gateCd} AS GATE_CD , #{BUYER_CD} AS BUYER_CD , #{BID_NUM} AS BID_NUM , #{BID_CNT} AS BID_CNT
) B ON ( A.GATE_CD = B.GATE_CD AND A.BUYER_CD = B.BUYER_CD AND A.BID_NUM = B.BID_NUM AND A.BID_CNT = B.BID_CNT ) WHEN MATCHED THEN UPDATE SET MOD_DATE = SYSDATE ,MOD_USER_ID = #{ses.userId} ,QTA_NUM = #{QTA_NUM}--QTA_NUM ,QTA_AMT = #{QTA_AMT}--QTA_AMT ,PRESUM_AMT = #{PRESUM_AMT}--PRESUM_AMT ,APP_DOC_NUM = #{APP_DOC_NUM}--APP_DOC_NUM ,APP_DOC_CNT = #{APP_DOC_CNT}--APP_DOC_CNT ,SIGN_STATUS = #{SIGN_STATUS}--SIGN_STATUS ,SIGN_DATE = #{SIGN_DATE}--SIGN_DATE ,ESTM_PRC1_ENC = #{ESTM_PRC1_ENC}--ESTM_PRC1_ENC ,ESTM_PRC2_ENC = #{ESTM_PRC2_ENC}--ESTM_PRC2_ENC ,ESTM_PRC3_ENC = #{ESTM_PRC3_ENC}--ESTM_PRC3_ENC ,ESTM_PRC4_ENC = #{ESTM_PRC4_ENC}--ESTM_PRC4_ENC ,ESTM_PRC5_ENC = #{ESTM_PRC5_ENC}--ESTM_PRC5_ENC ,ESTM_PRC6_ENC = #{ESTM_PRC6_ENC}--ESTM_PRC6_ENC ,ESTM_PRC7_ENC = #{ESTM_PRC7_ENC}--ESTM_PRC7_ENC ,ESTM_PRC8_ENC = #{ESTM_PRC8_ENC}--ESTM_PRC8_ENC ,ESTM_PRC9_ENC = #{ESTM_PRC9_ENC}--ESTM_PRC9_ENC ,ESTM_PRC10_ENC = #{ESTM_PRC10_ENC}--ESTM_PRC10_ENC ,ESTM_PRC11_ENC = #{ESTM_PRC11_ENC}--ESTM_PRC11_ENC ,ESTM_PRC12_ENC = #{ESTM_PRC12_ENC}--ESTM_PRC12_ENC ,ESTM_PRC13_ENC = #{ESTM_PRC13_ENC}--ESTM_PRC13_ENC ,ESTM_PRC14_ENC = #{ESTM_PRC14_ENC}--ESTM_PRC14_ENC ,ESTM_PRC15_ENC = #{ESTM_PRC15_ENC}--ESTM_PRC15_ENC ,ESTM_ENCKEY = #{ESTM_ENCKEY}--ESTM_ENCKEY ,ESTM_CERTV = #{ESTM_CERTV}--ESTM_CERTV ,ESTM_CERTNUM = #{ESTM_CERTNUM}--ESTM_CERTNUM ,ESTM_CONFIRM_DATE= #{ESTM_CONFIRM_DATE}--ESTM_CONFIRM_DATE ,ESTM_CONFIRM_TIME= #{ESTM_CONFIRM_TIME}--ESTM_CONFIRM_TIME ,ESTM_PRC1 = #{ESTM_PRC1}--ESTM_PRC1 ,ESTM_PRC2 = #{ESTM_PRC2}--ESTM_PRC2 ,ESTM_PRC3 = #{ESTM_PRC3}--ESTM_PRC3 ,ESTM_PRC4 = #{ESTM_PRC4}--ESTM_PRC4 ,ESTM_PRC5 = #{ESTM_PRC5}--ESTM_PRC5 ,ESTM_PRC6 = #{ESTM_PRC6}--ESTM_PRC6 ,ESTM_PRC7 = #{ESTM_PRC7}--ESTM_PRC7 ,ESTM_PRC8 = #{ESTM_PRC8}--ESTM_PRC8 ,ESTM_PRC9 = #{ESTM_PRC9}--ESTM_PRC9 ,ESTM_PRC10 = #{ESTM_PRC10}--ESTM_PRC10 ,ESTM_PRC11 = #{ESTM_PRC11}--ESTM_PRC11 ,ESTM_PRC12 = #{ESTM_PRC12}--ESTM_PRC12 ,ESTM_PRC13 = #{ESTM_PRC13}--ESTM_PRC13 ,ESTM_PRC14 = #{ESTM_PRC14}--ESTM_PRC14 ,ESTM_PRC15 = #{ESTM_PRC15}--ESTM_PRC15 ,CHOIC_ESTM_PRC1 = #{CHOIC_ESTM_PRC1}--CHOIC_ESTM_PRC1 ,CHOIC_ESTM_PRC2 = #{CHOIC_ESTM_PRC2}--CHOIC_ESTM_PRC2 ,CHOIC_ESTM_PRC3 = #{CHOIC_ESTM_PRC3}--CHOIC_ESTM_PRC3 ,CHOIC_ESTM_PRC4 = #{CHOIC_ESTM_PRC4}--CHOIC_ESTM_PRC4 ,FINAL_ESTM_PRC = #{FINAL_ESTM_PRC}--FINAL_ESTM_PRC ,ATT_FILE_NUM = #{ATT_FILE_NUM}--ATT_FILE_NUM ,RMK = #{RMK}--RMK WHEN NOT MATCHED THEN INSERT ( GATE_CD ,BUYER_CD ,BID_NUM ,BID_CNT ,REG_DATE ,REG_USER_ID ,MOD_DATE ,MOD_USER_ID ,DEL_FLAG ,QTA_NUM ,QTA_AMT ,PRESUM_AMT ,APP_DOC_NUM ,APP_DOC_CNT ,SIGN_STATUS ,SIGN_DATE ,ESTM_PRC1_ENC ,ESTM_PRC2_ENC ,ESTM_PRC3_ENC ,ESTM_PRC4_ENC ,ESTM_PRC5_ENC ,ESTM_PRC6_ENC ,ESTM_PRC7_ENC ,ESTM_PRC8_ENC ,ESTM_PRC9_ENC ,ESTM_PRC10_ENC ,ESTM_PRC11_ENC ,ESTM_PRC12_ENC ,ESTM_PRC13_ENC ,ESTM_PRC14_ENC ,ESTM_PRC15_ENC ,ESTM_ENCKEY ,ESTM_CERTV ,ESTM_CERTNUM ,ESTM_CONFIRM_DATE ,ESTM_CONFIRM_TIME ,ESTM_PRC1 ,ESTM_PRC2 ,ESTM_PRC3 ,ESTM_PRC4 ,ESTM_PRC5 ,ESTM_PRC6 ,ESTM_PRC7 ,ESTM_PRC8 ,ESTM_PRC9 ,ESTM_PRC10 ,ESTM_PRC11 ,ESTM_PRC12 ,ESTM_PRC13 ,ESTM_PRC14 ,ESTM_PRC15 ,CHOIC_ESTM_PRC1 ,CHOIC_ESTM_PRC2 ,CHOIC_ESTM_PRC3 ,CHOIC_ESTM_PRC4 ,FINAL_ESTM_PRC ,ATT_FILE_NUM ,RMK ) VALUES ( #{ses.gateCd}--GATE_CD ,#{BUYER_CD}--BUYER_CD ,#{BID_NUM}--BID_NUM ,#{BID_CNT}--BID_CNT ,SYSDATE--REG_DATE ,#{ses.userId}--REG_USER_ID ,SYSDATE--MOD_DATE ,#{ses.userId}--MOD_USER_ID ,'0'--DEL_FLAG ,#{QTA_NUM}--QTA_NUM ,#{QTA_AMT}--QTA_AMT ,#{PRESUM_AMT}--PRESUM_AMT ,#{APP_DOC_NUM}--APP_DOC_NUM ,#{APP_DOC_CNT}--APP_DOC_CNT ,#{SIGN_STATUS}--SIGN_STATUS ,#{SIGN_DATE}--SIGN_DATE ,#{ESTM_PRC1_ENC}--ESTM_PRC1_ENC ,#{ESTM_PRC2_ENC}--ESTM_PRC2_ENC ,#{ESTM_PRC3_ENC}--ESTM_PRC3_ENC ,#{ESTM_PRC4_ENC}--ESTM_PRC4_ENC ,#{ESTM_PRC5_ENC}--ESTM_PRC5_ENC ,#{ESTM_PRC6_ENC}--ESTM_PRC6_ENC ,#{ESTM_PRC7_ENC}--ESTM_PRC7_ENC ,#{ESTM_PRC8_ENC}--ESTM_PRC8_ENC ,#{ESTM_PRC9_ENC}--ESTM_PRC9_ENC ,#{ESTM_PRC10_ENC}--ESTM_PRC10_ENC ,#{ESTM_PRC11_ENC}--ESTM_PRC11_ENC ,#{ESTM_PRC12_ENC}--ESTM_PRC12_ENC ,#{ESTM_PRC13_ENC}--ESTM_PRC13_ENC ,#{ESTM_PRC14_ENC}--ESTM_PRC14_ENC ,#{ESTM_PRC15_ENC}--ESTM_PRC15_ENC ,#{ESTM_ENCKEY}--ESTM_ENCKEY ,#{ESTM_CERTV}--ESTM_CERTV ,#{ESTM_CERTNUM}--ESTM_CERTNUM ,#{ESTM_CONFIRM_DATE}--ESTM_CONFIRM_DATE ,#{ESTM_CONFIRM_TIME}--ESTM_CONFIRM_TIME ,#{ESTM_PRC1}--ESTM_PRC1 ,#{ESTM_PRC2}--ESTM_PRC2 ,#{ESTM_PRC3}--ESTM_PRC3 ,#{ESTM_PRC4}--ESTM_PRC4 ,#{ESTM_PRC5}--ESTM_PRC5 ,#{ESTM_PRC6}--ESTM_PRC6 ,#{ESTM_PRC7}--ESTM_PRC7 ,#{ESTM_PRC8}--ESTM_PRC8 ,#{ESTM_PRC9}--ESTM_PRC9 ,#{ESTM_PRC10}--ESTM_PRC10 ,#{ESTM_PRC11}--ESTM_PRC11 ,#{ESTM_PRC12}--ESTM_PRC12 ,#{ESTM_PRC13}--ESTM_PRC13 ,#{ESTM_PRC14}--ESTM_PRC14 ,#{ESTM_PRC15}--ESTM_PRC15 ,#{CHOIC_ESTM_PRC1}--CHOIC_ESTM_PRC1 ,#{CHOIC_ESTM_PRC2}--CHOIC_ESTM_PRC2 ,#{CHOIC_ESTM_PRC3}--CHOIC_ESTM_PRC3 ,#{CHOIC_ESTM_PRC4}--CHOIC_ESTM_PRC4 ,#{FINAL_ESTM_PRC}--FINAL_ESTM_PRC
